INSERT INTO `achievement_locale` (`ID`, `locale`, `Description_lang`, `Title_lang`, `Reward_lang`, `VerifiedBuild`) VALUES
(62773, 'ruRU', 'Заработайте все перечисленные ниже достижения глубоководной рыбалки.', 'Глубоководная рыбалка: новый соперник Джеджу', '', 67186),
(61883, 'ruRU', 'Трижды избегайте осаливания в течение первой минуты матча в \"Дуэли декораторов\"', 'Фокус с исчезновением', '', 67186),
(61887, 'ruRU', 'Получите все достижения \"Дуэли декораторов\".', 'Маскировка до зубов', '', 67186),
(61886, 'ruRU', 'Откройте все улучшения наборов в \"Дуэли декораторов\".', 'Для полного набора', '', 67186),
(61882, 'ruRU', 'Сбросьте эффект разоблачения в \"Дуэли декораторов\" до того, как вас осалят.', 'Насилу ушли', '', 67186),
(61881, 'ruRU', 'Останьтесь последним неосаленным игроком вашей команды в \"Дуэли декораторов\".', 'Тише воды', '', 67186),
(61880, 'ruRU', 'Прячьтесь в течение полутора минут подряд во время \"Дуэли декораторов\".', 'Так холодно в тени', '', 67186),
(61879, 'ruRU', 'Выиграйте раунд, осалив всех спрятавшихся игроков за две минуты во время \"Дуэли декораторов\".', 'Теперь ты води', '', 67186),
(61878, 'ruRU', 'Осальте игроков-противников в роли чародейского следопыта во время \"Дуэли декораторов\".', 'Попались', '', 67186),
(61793, 'ruRU', 'Осальте игроков-противников в роли нейтрализатора во время \"Дуэли декораторов\".', 'Набег из Бездны', '', 67186),
(61792, 'ruRU', 'Осальте игроков-противников в роли разрушителя чар во время \"Дуэли декораторов\".', 'Метка с надписью \"Плохо прячешься\"', '', 67186),
(63263, 'ruRU', '', '[DNT]Midnight Keystone Myth: Season One Personal Achievement', '', 67186),
(63097, 'ruRU', 'Добейтесь счета не менее 3400 в первом сезоне Midnight в режиме \"Эпохальный+\".', 'Эпохальный герой ключей Midnight: 1-й сезон', 'Звание \"Сумрачный претендент\" и предмет \"Затерянное во времени седло\"', 67186),
(61594, 'ruRU', 'Пройдите подземелье \"Небесный Путь\" с эпохальным ключом с лучшим результатом в своем регионе.', 'Триумфатор ключей: Небесный Путь', '', 67186),
(61593, 'ruRU', 'Пройдите подземелье \"Престол Триумвирата\" с эпохальным ключом с лучшим результатом в своем регионе.', 'Триумфатор ключей: Престол Триумвирата', '', 67186),
(61592, 'ruRU', 'Пройдите подземелье \"Яма Сарона\" с эпохальным ключом с лучшим результатом в своем регионе.', 'Триумфатор ключей: Яма Сарона', '', 67186),
(61591, 'ruRU', 'Пройдите подземелье \"Академия Алгет\'ар\" с эпохальным ключом с лучшим результатом в своем регионе.', 'Триумфатор ключей: академия Алгет\'ар', '', 67186),
(61590, 'ruRU', 'Пройдите подземелье \"Шпили Ветрокрылых\" с эпохальным ключом с лучшим результатом в своем регионе.', 'Триумфатор ключей: Шпиль Ветрокрылых', '', 67186),
(61589, 'ruRU', 'Пройдите подземелье \"Узел Нексуса Зенас\" с эпохальным ключом с лучшим результатом в своем регионе.', 'Триумфатор ключей: узел Нексуса Зенас', '', 67186),
(61588, 'ruRU', 'Пройдите подземелье \"Пещеры Маисара\" с эпохальным ключом с лучшим результатом в своем регионе.', 'Триумфатор ключей: пещеры Маисара', '', 67186),
(61587, 'ruRU', 'Пройдите подземелье \"Терраса Магистров\" (Midnight) с эпохальным ключом с лучшим результатом в своем регионе.', 'Триумфатор ключей: Терраса Магистров (Midnight)', '', 67186),
(61259, 'ruRU', 'Закончите 1-й сезон Midnight в режиме \"Эпохальный+\", попав в первые 0,1% игроков в вашем регионе.', 'Сумрачный герой: 1-й сезон Midnight', 'Звание: Сумрачный герой', 67186),
(61253, 'ruRU', 'Пройдите все подземелья с ключом \"Эпохальный+\" 30-го уровня за отведенное время в 1-м сезоне Midnight.', 'Midnight, 1-й сезон: прочность ключа – 30', 'Уровень ключей не опустится ниже 30-го до конца 1-го сезона Midnight.', 67186),
(61252, 'ruRU', 'Пройдите все подземелья с ключом \"Эпохальный+\" 29-го уровня за отведенное время в 1-м сезоне Midnight.', 'Midnight, 1-й сезон: прочность ключа – 29', 'Уровень ключей не опустится ниже 29-го до конца 1-го сезона Midnight.', 67186),
(61251, 'ruRU', 'Пройдите все подземелья с ключом \"Эпохальный+\" 28-го уровня за отведенное время в 1-м сезоне Midnight.', 'Midnight, 1-й сезон: прочность ключа – 28', 'Уровень ключей не опустится ниже 28-го до конца 1-го сезона Midnight.', 67186),
(61250, 'ruRU', 'Пройдите все подземелья с ключом \"Эпохальный+\" 27-го уровня за отведенное время в 1-м сезоне Midnight.', 'Midnight, 1-й сезон: прочность ключа – 27', 'Уровень ключей не опустится ниже 27-го до конца 1-го сезона Midnight.', 67186),
(61249, 'ruRU', 'Пройдите все подземелья с ключом \"Эпохальный+\" 26-го уровня за отведенное время в 1-м сезоне Midnight.', 'Midnight, 1-й сезон: прочность ключа – 26', 'Уровень ключей не опустится ниже 26-го до конца 1-го сезона Midnight.', 67186),
(61248, 'ruRU', 'Пройдите все подземелья с ключом \"Эпохальный+\" 25-го уровня за отведенное время в 1-м сезоне Midnight.', 'Midnight, 1-й сезон: прочность ключа – 25', 'Уровень ключей не опустится ниже 25-го до конца 1-го сезона Midnight.', 67186),
(61247, 'ruRU', 'Пройдите все подземелья с ключом \"Эпохальный+\" 24-го уровня за отведенное время в 1-м сезоне Midnight.', 'Midnight, 1-й сезон: прочность ключа – 24', 'Уровень ключей не опустится ниже 24-го до конца 1-го сезона Midnight.', 67186),
(61246, 'ruRU', 'Пройдите все подземелья с ключом \"Эпохальный+\" 23-го уровня за отведенное время в 1-м сезоне Midnight.', 'Midnight, 1-й сезон: прочность ключа – 23', 'Уровень ключей не опустится ниже 23-го до конца 1-го сезона Midnight.', 67186),
(61245, 'ruRU', 'Пройдите все подземелья с ключом \"Эпохальный+\" 22-го уровня за отведенное время в 1-м сезоне Midnight.', 'Midnight, 1-й сезон: прочность ключа – 22', 'Уровень ключей не опустится ниже 22-го до конца 1-го сезона Midnight.', 67186),
(61244, 'ruRU', 'Пройдите все подземелья с ключом \"Эпохальный+\" 21-го уровня за отведенное время в 1-м сезоне Midnight.', 'Midnight, 1-й сезон: прочность ключа – 21', 'Уровень ключей не опустится ниже 21-го до конца 1-го сезона Midnight.', 67186),
(61243, 'ruRU', 'Пройдите все подземелья с ключом \"Эпохальный+\" 20-го уровня за отведенное время в 1-м сезоне Midnight.', 'Midnight, 1-й сезон: прочность ключа – 20', 'Уровень ключей не опустится ниже 20-го до конца 1-го сезона Midnight.', 67186),
(61242, 'ruRU', 'Пройдите все подземелья с ключом \"Эпохальный+\" 19-го уровня за отведенное время в 1-м сезоне Midnight.', 'Midnight, 1-й сезон: прочность ключа – 19', 'Уровень ключей не опустится ниже 19-го до конца 1-го сезона Midnight.', 67186),
(61241, 'ruRU', 'Пройдите все подземелья с ключом \"Эпохальный+\" 18-го уровня за отведенное время в 1-м сезоне Midnight.', 'Midnight, 1-й сезон: прочность ключа – 18', 'Уровень ключей не опустится ниже 18-го до конца 1-го сезона Midnight.', 67186),
(61240, 'ruRU', 'Пройдите все подземелья с ключом \"Эпохальный+\" 17-го уровня за отведенное время в 1-м сезоне Midnight.', 'Midnight, 1-й сезон: прочность ключа – 17', 'Уровень ключей не опустится ниже 17-го до конца 1-го сезона Midnight.', 67186),
(61239, 'ruRU', 'Пройдите все подземелья с ключом \"Эпохальный+\" 16-го уровня за отведенное время в 1-м сезоне Midnight.', 'Midnight, 1-й сезон: прочность ключа – 16', 'Уровень ключей не опустится ниже 16-го до конца 1-го сезона Midnight.', 67186),
(61237, 'ruRU', 'Пройдите все подземелья с ключом \"Эпохальный+\" 15-го уровня за отведенное время в 1-м сезоне Midnight.', 'Midnight, 1-й сезон: прочность ключа – 15', 'Уровень ключей не опустится ниже 15-го до конца 1-го сезона Midnight.', 67186),
(61236, 'ruRU', 'Пройдите все подземелья с ключом \"Эпохальный+\" 14-го уровня за отведенное время в 1-м сезоне Midnight.', 'Midnight, 1-й сезон: прочность ключа – 14', 'Уровень ключей не опустится ниже 14-го до конца 1-го сезона Midnight.', 67186),
(61235, 'ruRU', 'Пройдите все подземелья с ключом \"Эпохальный+\" 13-го уровня за отведенное время в 1-м сезоне Midnight.', 'Midnight, 1-й сезон: прочность ключа – 13', 'Уровень ключей не опустится ниже 13-го до конца 1-го сезона Midnight.', 67186),
(61233, 'ruRU', 'Пройдите все подземелья с ключом \"Эпохальный+\" 12-го уровня за отведенное время в 1-м сезоне Midnight.', 'Midnight, 1-й сезон: прочность ключа – 12', 'Уровень ключей не опустится ниже 12-го до конца 1-го сезона Midnight.', 67186),
(12009, 'ruRU', 'Победите Л\'уру в Престоле Триумвирата в эпохальном режиме, когда все участники группы поражены сокрушающей тьмой.', 'Темная сторона', '', 67186),
(12005, 'ruRU', 'Заставьте Черноклыка уничтожить четыре запечатанных тайника Бездны, используя \"Прыжок тени\", после чего победите Сарпиша в Престоле Триумвирата в эпохальном режиме.', 'Не сдерживайся', '', 67186),
(12004, 'ruRU', 'Вызовите Урджада из мира Бездны с помощью прорыва Бездны, а затем победите его и Зураала Перерожденного в Престоле Триумвирата в эпохальном режиме.', 'Добро пожаловать в Бездну', '', 67186),
(9036, 'ruRU', 'Победите высшего мудреца Вирикс на Небесном Пути в героическом режиме, не уничтожая при этом големов-защитников.', 'Мономания', '', 67186),
(9035, 'ruRU', 'Сделайте в Небесном Пути в героическом режиме так, чтобы три кучки пепла одновременно превратились в солнечные вспышки в бою Рухраном.', 'И была вспышка', '', 67186),
(9034, 'ruRU', 'Победите усиленного голема в Небесном Пути в героическом режиме.', 'Увеличить… Усилить', '', 67186),
(9033, 'ruRU', 'Победите Ранжита в Небесном Пути в героическом режиме, не получая урона от следующих способностей: \"Вращающийся клинок\", \"Стена ветра\", \"Четыре ветра\" и \"Сфокусированный луч света\".', 'К рейду готов IV', '', 67186),
(4525, 'ruRU', 'Расчистите путь к Повелителю Плети Тиранию в Яме Сарона в героическом режиме. Во время первой попытки ни один участник рейда не должен получить урона от сосулек.', 'Носите каски', '', 67186),
(4524, 'ruRU', 'Убейте начальника кузни Гархлада в Яме Сарона в героическом режиме прежде, чем эффект \"Вечная мерзлота\" суммируется 11 раз на любом из игроков.', 'Не жди до одиннадцати!', '', 67186),
(62814, 'ruRU', '', '', '', 67186),
(62813, 'ruRU', '', '', '', 67186),
(62812, 'ruRU', '', '', '', 67186),
(62811, 'ruRU', '', '', '', 67186),
(62296, 'ruRU', '', 'Полученные гербы зари эпохи', '', 67186),
(42769, 'ruRU', 'Перерастите гербы зари героя во время 1-го сезона Midnight.', 'Герой зари', 'Награда: обмен гербов зари героя на гербы зари эпохи', 67186);
