INSERT INTO `currency_types_locale` (`ID`, `locale`, `Name_lang`, `Description_lang`, `VerifiedBuild`) VALUES
(3513, 'ruRU', 'Туманный сердечник Бездны', 'Можно трансмутировать в мощное снаряжение после победы над сильными врагами в рейдах 1-го сезона Midnight или прохождения эпохальных подземелий с ключом, многообещающих вылазок и охоты в кошмарном режиме.', 67186),
(3347, 'ruRU', 'Герб зари эпохи', 'Используется для улучшения эпохального снаряжения в ходе 1-го сезона Midnight до уровня предмета 276-289. \n\nПри использовании в процессе изготовления изменяет уровень итогового предмета на 272-285 в зависимости от качества.\n\nМожно получить, выполняя следующие задачи:\n\n- \"Шпиль Бездны\", \"Провал снов\", \"Марш на Кель\'Данас\" в эпохальном режиме\n- Подземелья с эпохальным ключом (уровень 9+)', 67186),
(3346, 'ruRU', 'Герб зари героя', 'Используется для улучшения снаряжения героя в ходе 1-го сезона Midnight до уровня предмета 263-276. Можно получить, выполняя следующие задачи:\n\n- \"Шпиль Бездны\", \"Провал снов\", \"Марш на Кель\'Данас\" в героическом режиме\n- Подземелья с эпохальным ключом (уровень 4-8)\n- Вылазки (уровень 11)\n- Трофей охотника за сокровищами (уровень 8+)\n- Охота (кошмарный режим)', 67186),
(3345, 'ruRU', 'Герб зари героя', 'Используется для улучшения снаряжения героя в ходе 1-го сезона Midnight до уровня предмета 263-276. \n\nПри использовании в процессе изготовления изменяет уровень итогового предмета на 259-272 в зависимости от качества.\n\nМожно получить, выполняя следующие задачи:\n\n- \"Шпиль Бездны\", \"Провал снов\", \"Марш на Кель\'Данас\" в героическом режиме\n- Подземелья с эпохальным ключом (уровень 4-8)\n- Вылазки (уровень 11)\n- Трофей охотника за сокровищами (уровень 8+)\n- Охота (кошмарный режим)', 67186),
(3344, 'ruRU', 'Герб зари защитника', 'Используется для улучшения снаряжения защитника в ходе 1-го сезона Midnight до уровня предмета 250-263. Можно получить, выполняя следующие задачи:\n\n- Еженедельные события в открытом мире\n- \"Шпиль Бездны\", \"Провал снов\", \"Марш на Кель\'Данас\" в обычном режиме\n- Сезонные подземелья в эпохальном режиме\nПодземелья с эпохальным ключом (уровень 2-3)\n- Вылазки (уровень 7-10)\n- Трофей охотника за сокровищами (уровень 6-7)\n- Охота (кошмарный режим)', 67186),
(3343, 'ruRU', 'Герб зари защитника', 'Используется для улучшения снаряжения защитника в ходе 1-го сезона Midnight до уровня предмета 250-263. Можно получить, выполняя следующие задачи:\n\n- Еженедельные события в открытом мире\n- \"Шпиль Бездны\", \"Провал снов\", \"Марш на Кель\'Данас\" в обычном режиме\n- Сезонные подземелья в эпохальном режиме\nПодземелья с эпохальным ключом (уровень 2-3)\n- Вылазки (уровень 7-10)\n- Трофей охотника за сокровищами (уровень 6-7)\n- Охота (кошмарный режим)', 67186),
(3342, 'ruRU', 'Герб зари ветерана', 'Используется для улучшения снаряжения ветерана в ходе 1-го сезона Midnight до уровня предмета 237-250. Можно получить, выполняя следующие задачи:\n\n- Повторяемые события в открытом мире\n- \"Шпиль Бездны\", \"Провал снов\", \"Марш на Кель\'Данас\" в режиме поиска рейда\n- Сезонные подземелья в героическом режиме\n- Вылазки (уровень 5-6)\n- Трофей охотника за сокровищами (уровень 4-5)\n- Охота (сложный режим)', 67186),
(3341, 'ruRU', 'Герб зари ветерана', 'Используется для улучшения снаряжения ветерана в ходе 1-го сезона Midnight до уровня предмета 237-250. \n\nПри использовании в процессе изготовления изменяет уровень итогового предмета на 233-246 в зависимости от качества.\n\nМожно получить, выполняя следующие задачи:\n\n- Повторяемые события в открытом мире\n- \"Шпиль Бездны\", \"Провал снов\", \"Марш на Кель\'Данас\" в режиме поиска рейда\n- Сезонные подземелья в героическом режиме\n- Вылазки (уровень 5-6)\n- Трофей охотника за сокровищами (уровень 4-5)\n- Охота (сложный режим)', 67186),
(3418, 'ruRU', 'Туманный сердечник Бездны', 'Можно трансмутировать в мощное снаряжение после победы над сильными врагами в рейдах 1-го сезона Midnight или прохождения эпохальных подземелий с ключом, многообещающих вылазок и охоты в кошмарном режиме.', 67186),
(3391, 'ruRU', 'Герб зари искателя приключений', 'Используется для улучшения снаряжения искателя приключений в ходе 1-го сезона Midnight до уровня предмета 224-237. Можно получить, выполняя следующие задачи:\n\n- Повторяемые события в открытом мире\n- Вылазки (уровень 4)\n- Охота (обычный режим)', 67186),
(3383, 'ruRU', 'Герб зари искателя приключений', 'Используется для улучшения снаряжения искателя приключений в ходе 1-го сезона Midnight до уровня предмета 224-237. \n\nПри использовании в процессе изготовления изменяет уровень итогового предмета на 220-233 в зависимости от качества.\n\nМожно получить, выполняя следующие задачи:\n\n- Повторяемые события в открытом мире\n- Вылазки (уровень 4)\n- Охота (обычный режим)', 67186),
(3348, 'ruRU', 'Герб зари эпохи', 'Используется для улучшения эпохального снаряжения в ходе 1-го сезона Midnight до уровня предмета 276-289. Можно получить, выполняя следующие задачи:\n\n- \"Шпиль Бездны\", \"Провал снов\", \"Марш на Кель\'Данас\" в героическом режиме\n- Подземелья с эпохальным ключом (уровень 9+)', 67186);
