(272125, 'ruRU', 'Золото, мракозарный мергель и предмет для текущей специализации в качестве приза за смекалку.', '', '', '', 'Тайник рекрута', 67186),
(263286, 'ruRU', '', '', '', '', 'Переделанный гонг грибостражей', 67186),
(273307, 'ruRU', 'Свежевыжатый лимонад, приготовленный отважным предпринимателем! В нем плавают кристаллики сахара... или это кристаллы маны?', '', '', '', 'Флакон лимонада отваги', 67186),
