INSERT INTO `journal_encounter_section_locale` (`ID`, `locale`, `Title_lang`, `BodyText_lang`, `VerifiedBuild`) VALUES
(32672, 'ruRU', 'Танки', '$bullet; Прозапасник копается в ближайшей горе ресурсов, применяя |cFF2959D3|Hspell:1235072|h[Использование ресурсов]|h|r.\n$bullet; При контакте гнилые грибы применяют эффект |cFF2959D3|Hspell:1234846|h[Отравляющие споры]|h|r, что предотвращает их |cFF2959D3|Hspell:1245593|h[гнилостный взрыв]|h|r.\n$bullet; |cFF2959D3|Hspell:1234681|h[Голодный рев]|h|r и |cFF2959D3|Hspell:1235125|h[Сытый рев]|h|r наносят значительный урон всем игрокам.', 67186),
(32669, 'ruRU', 'Обзор', 'Прозапасник готов защищать свое богатство любой ценой. Когда его уровень здоровья опускается до 90%, 60% и 30%, он решает |cFF2959D3|Hspell:1235072|h[использовать ресурсы]|h|r и усиливает одну из своих способностей.\n\nНакопив 100 ед. энергии, он начинает бросать на поле боя |cFF2959D3|Hspell:1234233|h[порченые припасы]|h|r, в течение 12 секунд выращивая гнилые грибы. Если на гриб наступить, игрока покрывают |cFF2959D3|Hspell:1234846|h[отравляющие споры]|h|r, – но при этом гриб уничтожается, и |cFF2959D3|Hspell:1245593|h[гнилостный взрыв]|h|r не происходит.', 67186),
(31527, 'ruRU', 'Запретный груз', 'Партия груза, спрятанная от любопытных глаз. Может послужить отличным укрытием.', 67186),
(31282, 'ruRU', 'Танк', '$bullet; Кистия обращает Грызунчик против игроков с помощью |cFF2959D3|Hspell:1230289|h[Темного насыщения]|h|r.\n$bullet; Избегайте |cFF2959D3|Hspell:1253811|h[Брызг Скверны]|h|r Грызунчик.\n$bullet; Прерывайте |cFF2959D3|Hspell:1264095|h[Зеркальные отражения]|h|r Кистии.', 67186),
(31281, 'ruRU', 'Лекари', '$bullet; Кистия обращает Грызунчик против игроков с помощью |cFF2959D3|Hspell:1230289|h[Темного насыщения]|h|r.\n$bullet; Избегайте |cFF2959D3|Hspell:1253811|h[Брызг Скверны]|h|r.\n$bullet; Когда на Кистию действует |cFF2959D3|Hspell:1265412|h[Дестабилизация]|h|r, она наносит значительный урон всем игрокам.', 67186),
(31280, 'ruRU', 'Бойцы', '$bullet; Кистия обращает Грызунчик против игроков с помощью |cFF2959D3|Hspell:1230289|h[Темного насыщения]|h|r.\n$bullet; Избегайте |cFF2959D3|Hspell:1253811|h[Брызг Скверны]|h|r Грызунчик.\n$bullet; Прерывайте |cFF2959D3|Hspell:1264095|h[Зеркальные отражения]|h|r Кистии.', 67186),
(35862, 'ruRU', 'Section 18', '', 67186),
(35353, 'ruRU', 'Раздел 17', '|n\nBy speaking with Lindormi near The Timeways portal or at the end of a Keystone Dungeon, characters with a tank specialization can enable |cFF2959D3|Hspell:1295986|h[Lindormi\'s Glow]|h|r when |cFF2959D3|Hspell:1278156|h[Lindormi\'s Guidance]|h|r is inactive.', 67186),
(34751, 'ruRU', 'Раздел 17', '', 67186),
(34733, 'ruRU', 'Вероломство Ксал\'атат', 'Ксал\'атат предает игроков и отменяет сделку, после чего каждая смерть отнимает 15 сек. от оставшегося времени.', 67186),
(34732, 'ruRU', 'Укрепленный', 'У противников, не являющихся боссами, на 20% больше здоровья. Они наносят на 20% больше урона.', 67186),
(34731, 'ruRU', 'Тиранический', 'У противников-боссов на 25% больше здоровья. Боссы и их прислужники наносят до 15% дополнительного урона.', 67186),
(34730, 'ruRU', '\"Тиранический\" и \"Укрепленный\"', 'Эти свойства дополнительно усиливают противников в подземельях с эпохальным ключом. Одно активируется на 7-м эпохальном уровне, а другое – на 10-м. Свойства меняются каждую неделю.', 67186),
(34727, 'ruRU', 'Сделка с Ксал\'атат: пожирание', '', 67186),
(34725, 'ruRU', 'Сделка с Ксал\'атат: слуга Бездны', '', 67186),
(34722, 'ruRU', 'Сделка с Ксал\'атат: пульсар', '', 67186),
(34720, 'ruRU', 'Эпохальный уровень: 6', '$bullet;Эффект |cFF2959D3|Hspell:1284818|h[Наставление Линдорми]|h|r снят.\n\nПерсонажи со специализацией \"Танк\" могут поговорить с Линдорми возле портала в Потоки времени или в конце подземелья, открытого с помощью эпохального ключа, чтобы получить |cFF2959D3|Hspell:1295986|h[Сияние Линдорми]|h|r, подсвечивающее противников.', 67186),
(35809, 'ruRU', 'Section 158', '', 67186),
(35491, 'ruRU', 'Раздел 69', '', 67186),
(35490, 'ruRU', 'Раздел 70', '', 67186),
(35489, 'ruRU', 'Раздел 76', '', 67186),
(35488, 'ruRU', 'Раздел 67', '$[!15,16\nВ героическом или более сложном режиме \"Гальванизация\" выпускает \"Чрезмерный поток\".$]', 67186),
(35477, 'ruRU', 'Раздел 22', '', 67186),
(35476, 'ruRU', 'Раздел 31', '', 67186),
(35475, 'ruRU', 'Раздел 30', '', 67186),
(35474, 'ruRU', 'Раздел 29', '', 67186),
(35473, 'ruRU', 'Раздел 31', '', 67186),
(35472, 'ruRU', 'Кристалл зари', 'Очищенный фрагмент наару, который могут подбирать игроки.\n$[!16\nВ эпохальном режиме кристаллы зари могут подвергнуться воздействию \"Погибели Света\".$]', 67186),
(35471, 'ruRU', 'Раздел 22', '', 67186),
