INSERT INTO `mail_template_locale` (`ID`, `locale`, `Body_lang`, `VerifiedBuild`) VALUES
(659, 'ruRU', 'Здравствуй, $gпослушник:послушница;!\n\nУзри ВЕЛИКОЛЕПНОЕ ИЗОБИЛИЕ этих земель! Оно неудержимо растет, множится, заполняет весь мир!\n\nТы преданно поклоняешься мне и за это заслуживаешь небольшой дар. В этот раз я ниспошлю тебе чистое изобилие!\n\nИ знай, $gдорогой послушник:дорогая послушница;, что теперь тебе могут встретиться новые подношения, включая конденсированную жизненную силу. Возможно, когда-нибудь ты найдешь их, если приключения заведут тебя в глубины Зул\'Амана.\n\nЖелаю тебе славной жатвы!\n\nДандан, лоа изобилия', 67186);
