INSERT INTO `trait_definition_locale` (`ID`, `locale`, `OverrideName_lang`, `OverrideSubtext_lang`, `OverrideDescription_lang`, `VerifiedBuild`) VALUES
(137688, 'ruRU', 'Педантичное перепроизводство', '', 'Вы лучше изучаете матрицы начертания, увеличивая вероятность изготовить дополнительные иллюзии или расходуемые предметы. $en1 повышается на $ev1 за каждое очко в этой специализации.', 67186),
(137685, 'ruRU', '', '', 'Перепроизводство дает до $ev1% дополнительных товаров при изготовлении расходуемых предметов.', 67186),
(137681, 'ruRU', '', '', 'Перепроизводство дает до $ev1% дополнительных товаров при изготовлении расходуемых предметов.', 67186),
(133669, 'ruRU', '', '', '$en1 повышается на $ev1 при изготовлении сплавов.|n|nОбучает применять завершающие реагенты при изготовлении сплавов.', 67186);
